var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 한 가지 묻고 싶은 게 있어요.","JPN":"リベット、一つ聞いてもよろしいですか？","ENG":"Rivet, there's a question I'd like to ask you.","TWN":"里維，我有個問題想問妳。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"두 가지 물어봐도 돼~ 친절한 리벳 선생님이 정답을 콕콕 찔러 줄 테니까~","JPN":"二つ聞いてもいいよ～。親切なリベット先生が正解を教えてあげるからさ～。","ENG":"You can ask two if you want. Ms. Rivet here will answer you kindly.","TWN":"問兩個也可以喔～親切的里維老師會一一告訴妳正確答案的～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일단 그 정신 사나운 쇳덩어리부터 내려놓고 이야기하죠.","JPN":"とりあえず、その物騒な鉄の塊を下ろしてから話しましょう。","ENG":"Will you put down that bulky metal chunk first please?","TWN":"總之先從那個兇殘的鐵塊開始說起吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"쇳덩어리라니 너무하네. 얘가 들으면 얼마나 서운해 하겠어.","JPN":"鉄の塊って酷い言い草だね。この子が聞いたら悲しむよ。","ENG":"Hey, that's rude. She's going to find it very offensive.","TWN":"竟然說是鐵塊，太過分了。這孩子聽見了會有多難過啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......설마 인공지능 모듈이라도 장착되어 있는 무기인가요?","JPN":"……まさか、人工知能モジュールでも搭載された武器なのですか？","ENG":"Oh, I didn't know it was equipped with an A.I. module.","TWN":"……那武器該不會是裝載了人工智慧模組吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아니? 그런 거 전혀 없는 완전 구식 쇳덩어린데?★","JPN":"ううん。そんなの一つも付いてない、超旧式な鉄の塊だけど？★","ENG":"It's not. It's a plain old chunk of metal. ★","TWN":"不是喔？完全沒有這種東西，完全是個舊式鐵塊喔？★"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......그래요. 그럴 줄 알았어요.","JPN":"……ですよね。そうだろうと思っていました。","ENG":"Okay. I thought so.","TWN":"……是嗎，我就知道。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그나저나, 언제부터 이 숲에 침식체들이 나타나기 시작했죠?","JPN":"ところで、いつからこの森に侵食体が現れ始めたのですか？","ENG":"My question is, when did Corrupted Objects start appearing in the forest?","TWN":"不過，這片森林裡是什麼時候開始出現侵蝕體的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 없는 동안 이 근방에 침식 재난 경보령이라도 발령됐나요?","JPN":"私がいない間に、この辺りに侵食災害警報でも発令されたのですか？","ENG":"Did they declare this place a Corruption Disaster area while I was gone?","TWN":"我不在的時候，周圍有發佈侵蝕災難警報嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뿌뿌뿝. 틀렸습니다. 레지나 학생.","JPN":"ブッブー。ハズレですね、レジーナくん。","ENG":"Bzzzzt! You're incorrect, Regina.","TWN":"噗噗，答錯囉，蕾佳娜同學。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"경보령 같은 거 발령된 적 없으니까 심각한 표정 짓지 마.","JPN":"警報なんて発令されてないから、そんな険しい顔しないでよ。","ENG":"That never happened, so you don't have to look so serious.","TWN":"沒有發佈什麼警報，所以別一臉嚴肅的樣子嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그냥 해가 지면 하급 침식체들이 어슬렁거리는 정도야.","JPN":"日が暮れたら下級侵食体がうろつく程度だからさ。","ENG":"When the sun goes down, those low class C.O.s come out for a stroll. That's all.","TWN":"只是太陽下山後，會有低等侵蝕體出來閒晃而已。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 그거잖아요! 침식체가 나타나면 경보령도 발령되겠죠!","JPN":"つまり、侵食体が日常的に現れるということですわね？\\n侵食体が現れたならば、警報が発令されるはずですわ！","ENG":"How is that any less concerning? They declare areas where there are Corrupted Objects disaster areas!","TWN":"那不就是嘛！有侵蝕體出現的話，就會發佈警報啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"관리국이 정식으로 선포한 적 없는데 어쩌겠어. 리플레이서 사태 때문에 여력이 없나 보지.","JPN":"管理局が正式に宣布しないんだから仕方ないよ。\\nリプレイサー騒動で忙しいんだろうね。","ENG":"Whatever you say, it was never made official by the Administration. Maybe they have their hands full because of the Replacer incident.","TWN":"管理局沒有正式宣佈過，又能怎麼辦呢。看來是因為克隆集團的事件，他們沒有餘力管這些了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"걱정 마. 여기 침식체들은 숲에서만 돌아다니고 사람 사는 데까지 쳐들어오진 않거든.","JPN":"心配いらないよ。ここの侵食体たちは\\n森から出ることも、人の住んでるところに現れることもないから。","ENG":"Don't worry. The C.O.s here don't raid houses; all they do is roam the forest.","TWN":"別擔心。這裡的侵蝕體只會在樹林裡徘徊，不會入侵人們生活的地方。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"고로 밤 늦게 돌아다니지만 않으면 안전해. 나 같은 용병에겐 완전 좋은 일이지.","JPN":"夜遅くに歩き回らなければ安全ってこと。アタシみたいな傭兵にはありがたいことだけどね。","ENG":"So you're safe if you stay home during the night. They're actually making things easier for mercenaries like me.","TWN":"所以只要晚上不要到這裡就很安全。對我這種傭兵來說，完全是件好事啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 그건 또 무슨 뜻이죠?","JPN":"それはどういう意味ですの？","ENG":"Huh? What’s that supposed to mean?","TWN":"咦？這又是什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"움직이는 건 뭐든 쏴 버려도 오발 사고 걱정할 필요 없으니까.","JPN":"動くものを見つけたら、確認しないで撃っても誤射する心配が無いからさ。","ENG":"I can open fire at anything that's moving without having to worry about accidents.","TWN":"因為即使看到有東西在動就開槍，也不會發生誤射意外啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이렇게!","JPN":"こんな風に！","ENG":"Like this!","TWN":"沒錯！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아자, 또 명중!","JPN":"よっしゃ、また命中！","ENG":"Yeah, bullseye!","TWN":"哎呀，又擊中了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이봐요! 당신 대체 무슨 짓이에요?!","JPN":"ちょっと！　何をしているのです！？","ENG":"Hey! What do you think you're doing?","TWN":"喂！妳到底在幹什麼啊？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이야~ 항상 느끼지만 무방비한 녀석들을 일방적으로 으깨 버리는 손맛은 정말 최고야~","JPN":"いや～、いつも思うんだけどさ……無防備な奴らを一方的に痛めつけるのってほんと最高だよね～。","ENG":"Ah, there's no better feeling than smashing their heads while they're unaware.","TWN":"哎呀～我一直覺得啊，單方面打爆這些毫無防備的傢伙，感覺真是棒透了～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"주의를 끌어서 어쩔 셈이에요! 숲에 있는 침식체를 모조리 불러들일 작정인가요?!","JPN":"注意を引き付けてどうするのですか！　森にいる侵食体を全部呼び寄せるつもりですの！？","ENG":"You're drawing attention to us! Are you going to take on the entire fleet of C.O.s in the forest?","TWN":"吸引它們的注意力幹什麼！妳是打算把樹林裡的侵蝕體全部引過來嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"왜? 간만에 집에 왔는데 겸사겸사 고향 땅을 어지럽히는 쓰레기들도 처리하면 좋잖아?","JPN":"いいじゃん。久しぶりに家に帰って来たんだから、ついでに故郷を荒らすクズどもを片付けとけば？","ENG":"What's the matter? You're finally home. Wouldn't it be nice if you helped take out the trash dirtying your hometown?","TWN":"怎麼了？好不容易回一次家，順便把這些擾亂故鄉的垃圾處理掉不是很好嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"나도 카운터 능력자를 공짜로 부리면서 돈도 벌고. 일석삼조네, 일석삼조.","JPN":"アタシもカウンター能力者をタダでこき使いながら金も稼げるし。一石三鳥だね、一石三鳥。","ENG":"And while you're at it, I get to order around a Counter and make some cash. That's like killing three birds with one stone.","TWN":"我也可以免費使喚制裁者一邊掙錢，這是一石三鳥啊，一石三鳥。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신, 마지막에 뭐라고 했죠?","JPN":"今、何て言いました？","ENG":"What did you say at the end there?","TWN":"妳，最後說了什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응? 아무 말도 안 했는데?","JPN":"え？　何も言ってないけど？","ENG":"Hm? I didn't say anything.","TWN":"嗯？我什麼都沒說啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그보다 저기 몰려온다! 화가 잔뜩 났네!","JPN":"ほら、押し寄せてくるよ！　おやおや、かなりお怒りみたいだね！","ENG":"There! They're coming at us! And they look angry!","TWN":"不說這個了，它們從那邊湧過來了！火氣不小啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"고향집 문턱 앞두고 객사하기 싫으면 최선을 다해야 할 거야! 꺄하하하핫!","JPN":"実家の門の一歩手前で野垂れ死にたくなかったら、全力で戦いな！　キャハハハハッ！","ENG":"You'd better fight hard if you don't want to be sent home in a casket! Kya hah hah hah!","TWN":"如果妳不想死在家門外，就得全力以赴囉！哈哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신 날 마중하러 나온 거라며!!","JPN":"私を迎えに来たのではなかったのですか！！","ENG":"You're supposed to help me get back home!","TWN":"妳不是來接我的嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"거기 서! 이 미치광이야!!","JPN":"待ちなさい！","ENG":"Stop right there, you maniac!","TWN":"給我站住！妳這個瘋子！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};